import{_ as l,o as e,c as r,a2 as i}from"./chunks/framework.DnrXFDHb.js";const y=JSON.parse('{"title":"🥈 白銀需求面深度分析","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/白銀研究/白銀研究_需求面分析.md","filePath":"Deep32Q知識庫/產業洞察/白銀研究/白銀研究_需求面分析.md"}'),a={name:"Deep32Q知識庫/產業洞察/白銀研究/白銀研究_需求面分析.md"};function n(o,t,s,g,d,h){return e(),r("div",null,[...t[0]||(t[0]=[i('<h1 id="🥈-白銀需求面深度分析" tabindex="-1">🥈 白銀需求面深度分析 <a class="header-anchor" href="#🥈-白銀需求面深度分析" aria-label="Permalink to &quot;🥈 白銀需求面深度分析&quot;">​</a></h1><blockquote><p><strong>最後更新</strong>：2026-06-11 <strong>資料來源</strong>：World Silver Survey 2026 (Silver Institute / Metals Focus), S&amp;P Global, TradingKey, 群益期貨</p></blockquote><hr><h2 id="一、白銀需求總覽" tabindex="-1">一、白銀需求總覽 <a class="header-anchor" href="#一、白銀需求總覽" aria-label="Permalink to &quot;一、白銀需求總覽&quot;">​</a></h2><p>白銀需求結構（2024-2026E, 百萬盎司）：</p><table tabindex="0"><thead><tr><th style="text-align:left;">需求類別</th><th style="text-align:right;">2024A</th><th style="text-align:right;">2025A</th><th style="text-align:right;">2026E</th><th style="text-align:left;">變化</th><th style="text-align:center;">佔比</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>工業需求</strong></td><td style="text-align:right;">677</td><td style="text-align:right;">657</td><td style="text-align:right;">~650</td><td style="text-align:left;">-3% YoY (2025)、-2% (2026E)</td><td style="text-align:center;">~58-60%</td></tr><tr><td style="text-align:left;">├ 太陽能光伏</td><td style="text-align:right;">232</td><td style="text-align:right;">187</td><td style="text-align:right;">151</td><td style="text-align:left;">-19% (2026E)</td><td style="text-align:center;">~14%</td></tr><tr><td style="text-align:left;">├ 電子/電氣</td><td style="text-align:right;">~240</td><td style="text-align:right;">~245</td><td style="text-align:right;">~250</td><td style="text-align:left;">+2-3%</td><td style="text-align:center;">~23%</td></tr><tr><td style="text-align:left;">├ 汽車 (含 EV)</td><td style="text-align:right;">~65</td><td style="text-align:right;">~70</td><td style="text-align:right;">~75</td><td style="text-align:left;">+7%</td><td style="text-align:center;">~7%</td></tr><tr><td style="text-align:left;">├ AI 資料中心</td><td style="text-align:right;">~10</td><td style="text-align:right;">~20</td><td style="text-align:right;">~35</td><td style="text-align:left;">+75%</td><td style="text-align:center;">~3%</td></tr><tr><td style="text-align:left;">└ 其他工業</td><td style="text-align:right;">~130</td><td style="text-align:right;">~135</td><td style="text-align:right;">~139</td><td style="text-align:left;">+3%</td><td style="text-align:center;">~13%</td></tr><tr><td style="text-align:left;"><strong>實物投資</strong></td><td style="text-align:right;">189</td><td style="text-align:right;">189</td><td style="text-align:right;"><strong>227</strong></td><td style="text-align:left;"><strong>+20%</strong></td><td style="text-align:center;"><strong>~21%</strong></td></tr><tr><td style="text-align:left;"><strong>珠寶首飾</strong></td><td style="text-align:right;">204</td><td style="text-align:right;">196</td><td style="text-align:right;">178</td><td style="text-align:left;">-9%</td><td style="text-align:center;">~17%</td></tr><tr><td style="text-align:left;"><strong>銀器/銀具</strong></td><td style="text-align:right;">56</td><td style="text-align:right;">54</td><td style="text-align:right;">~55</td><td style="text-align:left;">—</td><td style="text-align:center;">~5%</td></tr><tr><td style="text-align:left;"><strong>總需求</strong></td><td style="text-align:right;">~1,120</td><td style="text-align:right;">~1,090</td><td style="text-align:right;">~1,117</td><td style="text-align:left;">+2.5%</td><td style="text-align:center;">100%</td></tr></tbody></table><blockquote><p><strong>關鍵數據</strong>：2026 年白銀需求總量約 <strong>11.17 億盎司</strong>，供給約 <strong>10.50 億盎司</strong>，短缺 <strong>6,700 萬盎司</strong>，為連續第六年短缺。</p></blockquote><hr><h2 id="二、工業需求-佔比最大、增長最關鍵" tabindex="-1">二、工業需求（佔比最大、增長最關鍵） <a class="header-anchor" href="#二、工業需求-佔比最大、增長最關鍵" aria-label="Permalink to &quot;二、工業需求（佔比最大、增長最關鍵）&quot;">​</a></h2><h3 id="_2-1-太陽能光伏-—-佔工業需求-23-但正在「脫銀」" tabindex="-1">2.1 太陽能光伏 — 佔工業需求 23%，但正在「脫銀」 <a class="header-anchor" href="#_2-1-太陽能光伏-—-佔工業需求-23-但正在「脫銀」" aria-label="Permalink to &quot;2.1 太陽能光伏 — 佔工業需求 23%，但正在「脫銀」&quot;">​</a></h3><p>太陽能產業是過去三年白銀需求增長的最大引擎，但2026年出現轉折：</p><ul><li><strong>光伏銀需求</strong>：2024 年 232 Moz → 2025 年 187 Moz (-19% → 實際-6%) → 2026E <strong>151 Moz</strong> (-19%)</li><li>原因：<strong>低銀化技術奏效</strong>，單位銀耗大幅下降 <ul><li>PERC 電池銀耗：~100-120 mg/watt</li><li>TOPCon：~115-130 mg/watt（略高於 PERC）</li><li><strong>HJT</strong>（異質結）：75 mg/cell（2025 年 CPIA 數據，YoY -34.8%）</li><li><strong>銀包銅漿料</strong>：中試階段成本低 30-40%，若量產將進一步取代純銀</li></ul></li><li><strong>結果</strong>：儘管全球太陽能裝機量持續增長，白銀用量的增長正在<strong>脫鉤</strong></li></ul><blockquote><p>💡 <strong>關鍵洞察</strong>：太陽能是白銀需求中<strong>唯一出現結構性下降</strong>的類別。對於銀價長多論者，這是最需要解釋的矛盾點。</p></blockquote><h3 id="_2-2-電子-電氣-—-穩定增長" tabindex="-1">2.2 電子/電氣 — 穩定增長 <a class="header-anchor" href="#_2-2-電子-電氣-—-穩定增長" aria-label="Permalink to &quot;2.2 電子/電氣 — 穩定增長&quot;">​</a></h3><ul><li>年用量約 <strong>2.4-2.6 億盎司</strong></li><li>印刷電路板、半導體封裝、開關系統中的焊接/導電膏必不可少</li><li>半導體微型化趨勢使單位晶片銀用量略降，但<strong>晶片總量持續增長</strong></li><li>5G/6G 通訊設備 + 高速網路硬體推升需求</li></ul><h3 id="_2-3-ai-資料中心-—-新興增長極" tabindex="-1">2.3 AI 資料中心 — 新興增長極 <a class="header-anchor" href="#_2-3-ai-資料中心-—-新興增長極" aria-label="Permalink to &quot;2.3 AI 資料中心 — 新興增長極&quot;">​</a></h3><ul><li>Silver Institute 指出：AI 資料中心的擴張將成為白銀重要的新增需求</li><li><strong>高盛預測</strong>：到 2030 年全球資料中心電力消耗將比當前增長 <strong>165%</strong></li><li>若相關設施快速部署，<strong>額外將帶來約 6,750 萬盎司的銀需求</strong></li><li>白銀在資料中心中的應用：高導電性焊接、熱管理介面材料、高性能連接器</li><li>年增長率約 <strong>75%</strong>（但基期低，2026E 約 ~35 Moz）</li></ul><h3 id="_2-4-汽車-含電動車" tabindex="-1">2.4 汽車（含電動車） <a class="header-anchor" href="#_2-4-汽車-含電動車" aria-label="Permalink to &quot;2.4 汽車（含電動車）&quot;">​</a></h3><ul><li>2024 年全球 BEV+ PHEV 出貨 <strong>1,760 萬輛</strong>（BloombergNEF）</li><li>一輛傳統汽車約使用 0.5-1.0 oz 白銀（連接器、開關、感測器）</li><li>一輛電動車約使用 <strong>1.5-2.0 oz</strong>（更高電壓系統、更多感測器）</li><li>年增長率 ~7%</li></ul><hr><h2 id="三、實物投資需求-—-2026-年最大亮點" tabindex="-1">三、實物投資需求 — 2026 年最大亮點 <a class="header-anchor" href="#三、實物投資需求-—-2026-年最大亮點" aria-label="Permalink to &quot;三、實物投資需求 — 2026 年最大亮點&quot;">​</a></h2><ul><li>預計 <strong>+20%</strong> 至 2.27 億盎司，創 <strong>三年新高</strong></li><li>西方實物投資在連續三年下滑後 <strong>強勢復甦</strong></li><li>印度：白銀貨幣化（2026 年 4 月起白銀回歸貨幣地位）+ 投資需求續創新高</li><li>白銀 ETF（SLV 等）持有量 <strong>13.1 億盎司</strong></li></ul><p><strong>驅動力</strong>：</p><ul><li>白銀價格強勢表現（2025 年暴漲創歷史新高 + 2026 年續漲 11%）</li><li>宏觀不確定性（通膨、Fed 政策搖擺、地緣政治）</li><li>黃金/白銀 ratio 仍處於歷史高位的有利於白銀的均值回歸</li></ul><hr><h2 id="四、珠寶首飾需求-—-被高價抑制" tabindex="-1">四、珠寶首飾需求 — 被高價抑制 <a class="header-anchor" href="#四、珠寶首飾需求-—-被高價抑制" aria-label="Permalink to &quot;四、珠寶首飾需求 — 被高價抑制&quot;">​</a></h2><ul><li>2026E <strong>1.78 億盎司</strong>，<strong>-9%</strong> YoY，2020 年以來新低</li><li>創紀錄高價壓制以印度為首的主要市場消費</li><li><strong>例外</strong>：中國市場需求因產品設計創新 + 鍍金銀飾流行而小幅上升</li><li>珠寶需求具有<strong>可逆性</strong>：銀價若回落，珠寶需求將迅速反彈</li></ul><hr><h2 id="五、需求面總結" tabindex="-1">五、需求面總結 <a class="header-anchor" href="#五、需求面總結" aria-label="Permalink to &quot;五、需求面總結&quot;">​</a></h2><h3 id="📈-增長動能-正向" tabindex="-1">📈 增長動能（正向） <a class="header-anchor" href="#📈-增長動能-正向" aria-label="Permalink to &quot;📈 增長動能（正向）&quot;">​</a></h3><ol><li><strong>AI 資料中心</strong>：年增 75%，基期雖低但成長率驚人</li><li><strong>實物投資</strong>：2026 年 +20%，西方復甦、印度貨幣化</li><li><strong>汽車電氣化</strong>：EV 銀含量約為燃油車的 2-3 倍</li><li><strong>電子/電氣</strong>：穩定 ~2-3% YoY</li></ol><h3 id="📉-下行壓力-負向" tabindex="-1">📉 下行壓力（負向） <a class="header-anchor" href="#📉-下行壓力-負向" aria-label="Permalink to &quot;📉 下行壓力（負向）&quot;">​</a></h3><ol><li><strong>太陽能產業低銀化</strong>：-19% YoY，技術替代正在加速</li><li><strong>高價壓抑珠寶消費</strong>：-9% YoY，但具價格彈性，可望反彈</li></ol><h3 id="⚖️-平衡觀點" tabindex="-1">⚖️ 平衡觀點 <a class="header-anchor" href="#⚖️-平衡觀點" aria-label="Permalink to &quot;⚖️ 平衡觀點&quot;">​</a></h3><ul><li>工業需求整體預計下降 2%（至 6.5 億盎司四年低點）</li><li>但投資需求 +20% <strong>完全抵消工業需求下降</strong>且有餘</li><li><strong>總需求仍高於總供給，連續第六年短缺</strong></li></ul><blockquote><p>🔑 <strong>核心矛盾</strong>：太陽能正在「拋棄」白銀，但 AI 和投資需求正在「搶購」白銀。哪一股力量更強，將決定銀價的長期方向。</p></blockquote><hr><h2 id="六、資料來源" tabindex="-1">六、資料來源 <a class="header-anchor" href="#六、資料來源" aria-label="Permalink to &quot;六、資料來源&quot;">​</a></h2><ul><li>Silver Institute, World Silver Survey 2026</li><li>Silver Institute, Next Generation Metal (2025.12)</li><li>TradingKey, 白銀連續第六年出現供應缺口</li><li>群益期貨，白銀研究所：供應危機將延至 2026 年</li><li>pv magazine USA, Silver demand from PV industry expected to drop 19% this year</li><li>Reddit r/energy, Solar industry accelerates shift from silver</li><li>BofA Institute, Humanoid Robots 101 (cross-ref)</li></ul>',39)])])}const u=l(a,[["render",n]]);export{y as __pageData,u as default};
